mapper.select:
SELECT r.* FROM sys_role r
WHERE r.company_id = #{companyId}
AND r.id NOT IN (
    SELECT ur.role_id FROM sys_user_role ur WHERE ur.user_id = #{userId}
)

SELECT r.* FROM sys_role r
INNER JOIN sys_user_role ur ON r.id = ur.role_id
WHERE r.company_id = #{companyId}
AND ur.user_id = #{userId}
